exercises.solution:
from dataclasses import dataclass
from typing import List, Tuple

@dataclass
class Gate:
    name: str
    qubits: Tuple[int, ...]
    params: Tuple[float, ...] = ()

class SimpleCircuit:
    def __init__(self, n_qubits):
        self.n_qubits = n_qubits
        self.gates = []

    def h(self, q):
        self.gates.append(Gate('H', (q,)))
        return self

    def cx(self, c, t):
        self.gates.append(Gate('CX', (c, t)))
        return self

    def depth(self):
        layers = [0] * self.n_qubits
        for g in self.gates:
            max_layer = max(layers[q] for q in g.qubits)
            for q in g.qubits:
                layers[q] = max_layer + 1
        return max(layers)

qc = SimpleCircuit(2)
qc.h(0).cx(0, 1)
print(f"Depth: {qc.depth()}")
print(f"Gates: {qc.gates}")
